#ifdef ENABLE_DP
#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#endif

#ifdef ENABLE_HP
#pragma OPENCL EXTENSION cl_khr_fp16 : enable
#endif

#ifdef ENABLE_HP
#define CONV_INT(i) ((half2)((half)(i), (half)(i)))
#define EQUAL_T(a, b) (all((a) == (b)))
#else
#define CONV_INT(i) ((class_T)(i))
#define EQUAL_T(a, b) ((a) == (b))
#endif

#define MAD_T(a, b, c) ((a) * (b) + (c))

__kernel void benchmark_func(class_T seed, __global class_T* g_data) {
  const uint gid = get_global_id(0);
  const uint gsize = get_global_size(0);
  const uint lid = get_local_id(0);
  const uint group = get_group_id(0);

#ifdef BLOCK_STRIDED
  const uint stride = (uint)blockdim;
  const uint idx = group * (uint)blockdim * (uint)ELEMENTS_PER_THREAD + lid;
  const uint big_stride = gsize * (uint)ELEMENTS_PER_THREAD;
#else
  const uint stride = gsize;
  const uint idx = gid;
  const uint big_stride = gsize * (uint)ELEMENTS_PER_THREAD;
#endif

  class_T tmps[ELEMENTS_PER_THREAD];

  for (uint k = 0; k < (uint)FUSION_DEGREE; k++) {
    for (uint j = 0; j < (uint)ELEMENTS_PER_THREAD; j++) {
      tmps[j] = g_data[idx + j * stride + k * big_stride];
      for (uint i = 0; i < (uint)COMPUTE_ITERATIONS; i++) {
        tmps[j] = MAD_T(tmps[j], tmps[j], seed);
      }
    }

    class_T sum = CONV_INT(0);
    for (uint j = 0; j < (uint)ELEMENTS_PER_THREAD; j += 2) {
      sum = MAD_T(tmps[j], tmps[j + 1], sum);
    }

    if (EQUAL_T(sum, CONV_INT(-1))) {
      g_data[idx + k * big_stride] = sum;
    }
  }
}
